mapper.select:
SELECT id, room_id, user_id, ban_until, reason, created_by, created_at
FROM live_room_ban
WHERE room_id = #{roomId}
  AND user_id = #{userId}
  AND ban_until > #{now}
ORDER BY ban_until DESC
LIMIT 1

mapper.delete:
DELETE FROM live_room_ban
WHERE room_id = #{roomId}
  AND user_id = #{userId}
  AND ban_until > #{now}
